toolArgs.file_text:
@* Reads theme via CascadingParameter — works in static and interactive contexts *@

<span class="theme-indicator" style="color: @(Theme?.AccentColor ?? "#0d6efd");">
    @GetThemeIcon() @(Theme?.Theme.ToString() ?? "Light")
</span>

@code {
    [CascadingParameter]
    private ThemeInfo? Theme { get; set; }

    private string GetThemeIcon() => Theme?.Theme switch
    {
        Theme.Dark => "🌙",
        Theme.System => "💻",
        _ => "☀️"
    };
}

@page "/settings"
@rendermode InteractiveServer
@inject CascadingValueSource<ThemeInfo> ThemeSource

<PageTitle>Settings</PageTitle>

<h1>User Preferences</h1>

<div class="mb-3">
    <label class="form-label fw-bold">Theme</label>
    <div class="btn-group d-block" role="group">
        @foreach (var theme in Enum.GetValues<Theme>())
        {
            <button type="button"
                    class="btn @(theme == currentTheme ? "btn-primary" : "btn-outline-primary")"
                    @onclick="() => SetTheme(theme)">
                @GetIcon(theme) @theme
            </button>
        }
    </div>
</div>

<div class="mb-3">
    <label class="form-label fw-bold">Accent Color</label>
    <div class="d-flex align-items-center gap-2">
        <input type="color" class="form-control form-control-color"
               value="@currentAccentColor"
               @onchange="OnAccentColorChanged" />
        <span>@currentAccentColor</span>
    </div>
</div>

<div class="mt-4 p-3 border rounded" style="border-color: @currentAccentColor !important;">
    <h5 style="color: @currentAccentColor;">Preview</h5>
    <p>Current theme: @GetIcon(currentTheme) @currentTheme</p>
    <p>Accent color: <span style="color: @currentAccentColor;">■ @currentAccentColor</span></p>
</div>

@code {
    [CascadingParameter]
    private ThemeInfo? Theme { get; set; }

    private Theme currentTheme;
    private string currentAccentColor = "#0d6efd";

    protected override void OnParametersSet()
    {
        if (Theme is not null)
        {
            currentTheme = Theme.Theme;
            currentAccentColor = Theme.AccentColor;
        }
    }

    private async Task SetTheme(Theme theme)
    {
        currentTheme = theme;
        await PublishChange();
    }

    private async Task OnAccentColorChanged(ChangeEventArgs e)
    {
        currentAccentColor = e.Value?.ToString() ?? "#0d6efd";
        await PublishChange();
    }

    private async Task PublishChange()
    {
        var updated = new ThemeInfo
        {
            Theme = currentTheme,
            AccentColor = currentAccentColor
        };
        await ThemeSource.NotifyChangedAsync(updated);
    }

    private static string GetIcon(Theme theme) => theme switch
    {
        Theme.Dark => "🌙",
        Theme.System => "💻",
        _ => "☀️"
    };
}

